var surah053 = {
  number: 53,
  nameArabic: "an-Najm",
  nameEnglish: "An-Najm",
  meaning: "The Star",
  totalAyahs: 62,
  ayahs: [
    { number: 1, arabic: "وَٱلنَّجْمِ إِذَا هَوَىٰ", transliteration: "Waalnnajmi itha hawa", transliterationB: "Wannajmi izaa hawaa", english: "By the Star when it goes down", romanUrdu: "Kasam hai taare ki jabke woh guroob hua" },
    { number: 2, arabic: "مَا ضَلَّ صَاحِبُكُمْ وَمَا غَوَىٰ", transliteration: "Ma dalla sahibukum wama ghawa", transliterationB: "Maa dalla saahibukum wa maa ghawaa", english: "Your Companion is neither astray nor being misled", romanUrdu: "Tumhara rafeeq(companion) na bhatka hai na behka(deluded) hai" },
    { number: 3, arabic: "وَمَا يَنطِقُ عَنِ ٱلْهَوَىٰٓ", transliteration: "Wama yantiqu AAani alhawa", transliterationB: "Wa maa yyantiqu 'anilhawaaa", english: "Nor does he say (aught) of (his own) Desire", romanUrdu: "Woh apni khwaish-e-nafs se nahin bolta" },
    { number: 4, arabic: "إِنْ هُوَ إِلَّا وَحْىٌۭ يُوحَىٰ", transliteration: "In huwa illa wahyun yooha", transliterationB: "In huwa illaa Wahyuny yoohaa", english: "It is no less than inspiration sent down to him", romanUrdu: "Yeh to ek wahee (Inspiration /revelation) hai jo uspar nazil ki jati hai" },
    { number: 5, arabic: "عَلَّمَهُۥ شَدِيدُ ٱلْقُوَىٰ", transliteration: "AAallamahu shadeedu alquwa", transliterationB: "Allamahoo shadeedul quwaa", english: "He was taught by one Mighty in Power", romanUrdu: "Usey zabardast quwwat waley ne taleem di hai" },
    { number: 6, arabic: "ذُو مِرَّةٍۢ فَٱسْتَوَىٰ", transliteration: "Thoo mirratin faistawa", transliterationB: "Zoo mirratin fastawaa", english: "Endued with Wisdom: for he appeared (in stately form)", romanUrdu: "Jo bada sahib-e-hikmat hai" },
    { number: 7, arabic: "وَهُوَ بِٱلْأُفُقِ ٱلْأَعْلَىٰ", transliteration: "Wahuwa bialofuqi alaAAla", transliterationB: "Wa huwa bil ufuqil a'laa", english: "While he was in the highest part of the horizon", romanUrdu: "Woh saamne aa khada hua jabke woh balaii ufuq par tha(highest part of the horizon)" },
    { number: 8, arabic: "ثُمَّ دَنَا فَتَدَلَّىٰ", transliteration: "Thumma dana fatadalla", transliterationB: "Summa danaa fatadalla", english: "Then he approached and came closer", romanUrdu: "Phir kareeb aaya aur upar muallak ho gaya.(approached and descended)" },
    { number: 9, arabic: "فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَىٰ", transliteration: "Fakana qaba qawsayni aw adna", transliterationB: "Fakaana qaaba qawsaini aw adnaa", english: "And was at a distance of but two bow-lengths or (even) nearer", romanUrdu: "Yahan tak ke do kamano (bow lengths) ke barabar ya issey kuch kam faasla reh gaya" },
    { number: 10, arabic: "فَأَوْحَىٰٓ إِلَىٰ عَبْدِهِۦ مَآ أَوْحَىٰ", transliteration: "Faawha ila AAabdihi ma awha", transliterationB: "Fa awhaaa ilaa 'abdihee maaa awhaa", english: "So did (Allah) convey the inspiration to His Servant- (conveyed) what He (meant) to convey", romanUrdu: "Tab usne Allah ke banday ko wahee (revelation) pahunchayi jo wahee (revelation) bhi usey pahunchani thi" },
    { number: 11, arabic: "مَا كَذَبَ ٱلْفُؤَادُ مَا رَأَىٰٓ", transliteration: "Ma kathaba alfuadu ma raa", transliterationB: "Maa kazabal fu'aadu maa ra aa", english: "The (Prophet's) (mind and) heart in no way falsified that which he saw", romanUrdu: "Nazar ne jo kuch dekha, dil ne usmein jhoot na milaya" },
    { number: 12, arabic: "أَفَتُمَٰرُونَهُۥ عَلَىٰ مَا يَرَىٰ", transliteration: "Afatumaroonahu AAala ma yara", transliterationB: "Afatumaaroonahoo 'alaa maayaraa", english: "Will ye then dispute with him concerning what he saw", romanUrdu: "Ab kya tum us cheez par ussey jhagadte ho jisey woh aankhon se dekhta hai" },
    { number: 13, arabic: "وَلَقَدْ رَءَاهُ نَزْلَةً أُخْرَىٰ", transliteration: "Walaqad raahu nazlatan okhra", transliterationB: "Wa laqad ra aahu nazlatan ukhraa", english: "For indeed he saw him at a second descent", romanUrdu: "Aur ek martaba phir usney" },
    { number: 14, arabic: "عِندَ سِدْرَةِ ٱلْمُنتَهَىٰ", transliteration: "AAinda sidrati almuntaha", transliterationB: "Inda sidratil muntaha", english: "Near the Lote-tree beyond which none may pass", romanUrdu: "Sidratul muntaha ke paas usko (Angel Gibriel) dekha" },
    { number: 15, arabic: "عِندَهَا جَنَّةُ ٱلْمَأْوَىٰٓ", transliteration: "AAindaha jannatu almawa", transliterationB: "Indahaa jannatul maawaa", english: "Near it is the Garden of Abode", romanUrdu: "Jahan paas hi jannat-ul-maawa hai" },
    { number: 16, arabic: "إِذْ يَغْشَى ٱلسِّدْرَةَ مَا يَغْشَىٰ", transliteration: "Ith yaghsha alssidrata ma yaghsha", transliterationB: "Iz yaghshas sidrata maa yaghshaa", english: "Behold, the Lote-tree was shrouded (in mystery unspeakable)", romanUrdu: "Us waqt sidrah par chaa raha tha jo kuch ke chaa raha tha" },
    { number: 17, arabic: "مَا زَاغَ ٱلْبَصَرُ وَمَا طَغَىٰ", transliteration: "Ma zagha albasaru wama tagha", transliterationB: "Maa zaaghal basaru wa maa taghaa", english: "(His) sight never swerved, nor did it go wrong", romanUrdu: "Nigaah na chundhyayi (waver / swerve) na hadd se mutajawiz (transgress) hui" },
    { number: 18, arabic: "لَقَدْ رَأَىٰ مِنْ ءَايَٰتِ رَبِّهِ ٱلْكُبْرَىٰٓ", transliteration: "Laqad raa min ayati rabbihi alkubra", transliterationB: "Laqad ra aa min aayaati Rabbihil kubraaa", english: "For truly did he see, of the Signs of his Lord, the Greatest", romanUrdu: "Aur usney apne Rubb ki badi badi nishaniyan dekhi" },
    { number: 19, arabic: "أَفَرَءَيْتُمُ ٱللَّٰتَ وَٱلْعُزَّىٰ", transliteration: "Afaraaytumu allata waalAAuzza", transliterationB: "Afara'aytumul laata wal 'uzzaa", english: "Have ye seen Lat. and 'Uzza", romanUrdu: "Ab zara batao , tumne kabhi is Laat aur is Uzza (names of pagan idols)" },
    { number: 20, arabic: "وَمَنَوٰةَ ٱلثَّالِثَةَ ٱلْأُخْرَىٰٓ", transliteration: "Wamanata alththalithata alokhra", transliterationB: "Wa manaatas saalisatal ukhraa", english: "And another, the third (goddess), Manat", romanUrdu: "Aur tisri (third) ek aur devi Manaat ki haqeeqat par kuch gaur bhi kiya" },
    { number: 21, arabic: "أَلَكُمُ ٱلذَّكَرُ وَلَهُ ٱلْأُنثَىٰ", transliteration: "Alakumu alththakaru walahu alontha", transliterationB: "A-lakumuz zakaru wa lahul unsaa", english: "What! for you the male sex, and for Him, the female", romanUrdu: "Kya betay (sons) tumhare liye hain aur betiyan (daughters) khuda ke liye" },
    { number: 22, arabic: "تِلْكَ إِذًۭا قِسْمَةٌۭ ضِيزَىٰٓ", transliteration: "Tilka ithan qismatun deeza", transliterationB: "Tilka izan qismatun deezaa", english: "Behold, such would be indeed a division most unfair", romanUrdu: "Yeh to badi dhandhli (unjust/unfair) ki taqseem hui" },
    { number: 23, arabic: "إِنْ هِىَ إِلَّآ أَسْمَآءٌۭ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّآ أَنزَلَ ٱللَّهُ بِهَا مِن سُلْطَٰنٍ ۚ إِن يَتَّبِعُونَ إِلَّا ٱلظَّنَّ وَمَا تَهْوَى ٱلْأَنفُسُ ۖ وَلَقَدْ جَآءَهُم مِّن رَّبِّهِمُ ٱلْهُدَىٰٓ", transliteration: "In hiya illa asmaon sammaytumooha antum waabaokum ma anzala Allahu biha min sultanin in yattabiAAoona illa alththanna wama tahwa alanfusu walaqad jaahum min rabbihimu alhuda", transliterationB: "In hiya illaaa asmaaa'un sammaitumoohaaa antum wa aabaaa'ukum maaa anzalal laahu bihaa min sultaan; inyyattabi'oona illaz zanna wa maa tahwal anfusu wa laqad jaaa'ahum mir Rabbihimul hudaa", english: "These are nothing but names which ye have devised,- ye and your fathers,- for which Allah has sent down no authority (whatever). They follow nothing but conjecture and what their own souls desire!- Even though there has already come to them Guidance from their Lord", romanUrdu: "Darasal yeh kuch nahin hain magar bas chandh naam jo tumne aur tumhare baap dada ne rakh liye hain. Allah ne inke liye koi sanad nazil nahin ki. Haqeeat yeh hai ke log mehez weham-o-gumaan ki pairvi kar rahey hain aur khwahishaat-e-nafs ke mureed bane huey hain, halanke unke Rubb ki taraf se unke paas hidayat aa chuki hai" },
    { number: 24, arabic: "أَمْ لِلْإِنسَٰنِ مَا تَمَنَّىٰ", transliteration: "Am lilinsani ma tamanna", transliterationB: "Am lil insaani maa taman naa", english: "Nay, shall man have (just) anything he hankers after", romanUrdu: "Kya insaan jo kuch chaahe uske liye wahi haqq hai" },
    { number: 25, arabic: "فَلِلَّهِ ٱلْءَاخِرَةُ وَٱلْأُولَىٰ", transliteration: "Falillahi alakhiratu waaloola", transliterationB: "Falillaahil aakhiratu wal oolaa", english: "But it is to Allah that the End and the Beginning (of all things) belong", romanUrdu: "Duniya aur aakhirat ka maalik to Allah hi hai" },
    { number: 26, arabic: "۞ وَكَم مِّن مَّلَكٍۢ فِى ٱلسَّمَٰوَٰتِ لَا تُغْنِى شَفَٰعَتُهُمْ شَيْـًٔا إِلَّا مِنۢ بَعْدِ أَن يَأْذَنَ ٱللَّهُ لِمَن يَشَآءُ وَيَرْضَىٰٓ", transliteration: "Wakam min malakin fee alssamawati la tughnee shafaAAatuhum shayan illa min baAAdi an yathana Allahu liman yashao wayarda", transliterationB: "Wa kam mim malakin fissamaawaati laa tughnee shafaa'atuhum shai'an illaa mim ba'di anyyaazanal laahu limany yashaaa'u wa yardaa", english: "How many-so-ever be the angels in the heavens, their intercession will avail nothing except after Allah has given leave for whom He pleases and that he is acceptable to Him", romanUrdu: "Aasmano mein kitne hi farishte maujood hain, un ki shafaat (intercession) kuch bhi kaam nahin aa sakti jab tak ke Allah kisi aisey shaks ke haqq mein uski ijazat na dey jiske liye woh koi arzdaasht (plea) sunna chahe aur usko pasand karey" },
    { number: 27, arabic: "إِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ لَيُسَمُّونَ ٱلْمَلَٰٓئِكَةَ تَسْمِيَةَ ٱلْأُنثَىٰ", transliteration: "Inna allatheena la yuminoona bialakhirati layusammoona almalaikata tasmiyata alontha", transliterationB: "innal lazeena laa yu'minoona bil aakhirati la yusammoonal malaaa'ikata tasmiyatal unsaa", english: "Those who believe not in the Hereafter, name the angels with female names", romanUrdu: "Magar jo log aakhirat ko nahin maante woh farishton ko deviyon (godess) ke naamo se mausoom karte hain" },
    { number: 28, arabic: "وَمَا لَهُم بِهِۦ مِنْ عِلْمٍ ۖ إِن يَتَّبِعُونَ إِلَّا ٱلظَّنَّ ۖ وَإِنَّ ٱلظَّنَّ لَا يُغْنِى مِنَ ٱلْحَقِّ شَيْـًۭٔا", transliteration: "Wama lahum bihi min AAilmin in yattabiAAoona illa alththanna wainna alththanna la yughnee mina alhaqqi shayan", transliterationB: "Wa maa lahum bihee min 'ilmin iny yattabi'oona illaz zanna wa innaz zanna laa yughnee minal haqqi shai'aa", english: "But they have no knowledge therein. They follow nothing but conjecture; and conjecture avails nothing against Truth", romanUrdu: "Halaanke is maamle ka koi ilm (knowledge) unhein haasil nahin hai. Woh mehez gumaan ki pairvi kar rahey hain, aur gumaan haqq ki jagah kuch bhi kaam nahin de sakta" },
    { number: 29, arabic: "فَأَعْرِضْ عَن مَّن تَوَلَّىٰ عَن ذِكْرِنَا وَلَمْ يُرِدْ إِلَّا ٱلْحَيَوٰةَ ٱلدُّنْيَا", transliteration: "FaaAArid AAan man tawalla AAan thikrina walam yurid illa alhayata alddunya", transliterationB: "Fa a'rid 'am man tawallaa 'an zikrinaa wa lam yurid illal hayaatad dunyaa", english: "Therefore shun those who turn away from Our Message and desire nothing but the life of this world", romanUrdu: "Pas aey Nabi, jo shaks hamarey zikr se mooh pherta hai, aur duniya ki zindagi ke siwa jise kuch matloob nahin hai, usey uske haal par chodh do" },
    { number: 30, arabic: "ذَٰلِكَ مَبْلَغُهُم مِّنَ ٱلْعِلْمِ ۚ إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِمَن ضَلَّ عَن سَبِيلِهِۦ وَهُوَ أَعْلَمُ بِمَنِ ٱهْتَدَىٰ", transliteration: "Thalika mablaghuhum mina alAAilmi inna rabbaka huwa aAAlamu biman dalla AAan sabeelihi wahuwa aAAlamu bimani ihtada", transliterationB: "Zalika mablaghuhum minal 'ilm; inna rabbaka huwa a'lamu biman dalla 'an sabee lihee wa huwa a'lamu bimanih tadaa", english: "That is as far as knowledge will reach them. Verily thy Lord knoweth best those who stray from His Path, and He knoweth best those who receive guidance", romanUrdu: "In logon ka mablag-e-ilm (utmost of their knowledge) bas yahi kuch hai, yeh baat tera Rubb hi zyada jaanta hai ke uske raaste se kaun bhatak gaya hai aur kaun seedhe raaste par hai" },
    { number: 31, arabic: "وَلِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ لِيَجْزِىَ ٱلَّذِينَ أَسَٰٓـُٔوا۟ بِمَا عَمِلُوا۟ وَيَجْزِىَ ٱلَّذِينَ أَحْسَنُوا۟ بِٱلْحُسْنَى", transliteration: "Walillahi ma fee alssamawati wama fee alardi liyajziya allatheena asaoo bima AAamiloo wayajziya allatheena ahsanoo bialhusna", transliterationB: "Wa lillaahi maa fis samaawaati wa maa fil ardi liyajziyal lazeena asaaa'oo bimaa 'amiloo wa yajziyal lazeena ahsanoo bilhusnaa", english: "Yea, to Allah belongs all that is in the heavens and on earth: so that He rewards those who do evil, according to their deeds, and He rewards those who do good, with what is best", romanUrdu: "Aur zameen aur aasmaano ki har cheez ka maalik Allah hi hai. Taa-ke Allah burayi karne waalon ko unke amal ka badla de aur un logon ko acchi jaza se nawaze jinhon ne neik rawayya ikhtiyar kiya hai" },
    { number: 32, arabic: "ٱلَّذِينَ يَجْتَنِبُونَ كَبَٰٓئِرَ ٱلْإِثْمِ وَٱلْفَوَٰحِشَ إِلَّا ٱللَّمَمَ ۚ إِنَّ رَبَّكَ وَٰسِعُ ٱلْمَغْفِرَةِ ۚ هُوَ أَعْلَمُ بِكُمْ إِذْ أَنشَأَكُم مِّنَ ٱلْأَرْضِ وَإِذْ أَنتُمْ أَجِنَّةٌۭ فِى بُطُونِ أُمَّهَٰتِكُمْ ۖ فَلَا تُزَكُّوٓا۟ أَنفُسَكُمْ ۖ هُوَ أَعْلَمُ بِمَنِ ٱتَّقَىٰٓ", transliteration: "Allatheena yajtaniboona kabaira alithmi waalfawahisha illa allamama inna rabbaka wasiAAu almaghfirati huwa aAAlamu bikum ith anshaakum mina alardi waith antum ajinnatun fee butooni ommahatikum fala tuzakkoo anfusakum huwa aAAlamu bimani ittaqa", transliterationB: "Allazeena yajtaniboona kabaaa'iral ismi walfawaa hisha illal lamam; inna rabbaka waasi'ul maghfirah; huwa a'lamu bikum iz ansha akum minal ardi wa iz antum ajinnatun fee butooni umma haatikum falaa tuzakkooo anfusakum huwa a'lamu bimanit taqaa", english: "Those who avoid great sins and shameful deeds, only (falling into) small faults,- verily thy Lord is ample in forgiveness. He knows you well when He brings you out of the earth, And when ye are hidden in your mothers' wombs. Therefore justify not yourselves: He knows best who it is that guards against evil", romanUrdu: "Jo badey badey gunahon aur khule khule qabeeh afaal (shameful deeds) se parheiz karte hain, illa yeh ke kuch kasoor unse sarzad ho jaye. Bila shubhah tere Rubb ka daaman-e-magfirat bahut waseeh hai. Woh tumhein us waqt se khoob jaanta hai jab usne zameen se tumhein paida kiya, aur jab tum apni maaon (mothers) ke paiton (wombs) mein abhi janin (fetuses) hi thay. Pas apne nafs ki paaki ke daawe na karo. Wahi behtar jaanta hai ke waqai muttaqi kaun hai" },
    { number: 33, arabic: "أَفَرَءَيْتَ ٱلَّذِى تَوَلَّىٰ", transliteration: "Afaraayta allathee tawalla", transliterationB: "Afara'ayatal lazee tawallaa", english: "Seest thou one who turns back", romanUrdu: "Phir aey Nabi, tumne us shaks ko bhi dekha jo raah-e-khuda se phir gaya" },
    { number: 34, arabic: "وَأَعْطَىٰ قَلِيلًۭا وَأَكْدَىٰٓ", transliteration: "WaaAAta qaleelan waakda", transliterationB: "Wa a'taa qaleelanw wa akdaa", english: "Gives a little, then hardens (his heart)", romanUrdu: "Aur thoda sa de kar ruk gaya" },
    { number: 35, arabic: "أَعِندَهُۥ عِلْمُ ٱلْغَيْبِ فَهُوَ يَرَىٰٓ", transliteration: "aAAindahu AAilmu alghaybi fahuwa yara", transliterationB: "A'indahoo 'ilmul ghaibi fahuwa yaraa", english: "What! Has he knowledge of the Unseen so that he can see", romanUrdu: "Kya uske paas gaib ka ilm hai ke woh haqeeqat ko dekh raha hai" },
    { number: 36, arabic: "أَمْ لَمْ يُنَبَّأْ بِمَا فِى صُحُفِ مُوسَىٰ", transliteration: "Am lam yunabba bima fee suhufi moosa", transliterationB: "Am lam yunabbaa bimaa fee suhuhfi Moosa", english: "Nay, is he not acquainted with what is in the Books of Moses", romanUrdu: "Kya usey un baaton ki koi khabar nahin pahunchi jo moosa ke sahifon" },
    { number: 37, arabic: "وَإِبْرَٰهِيمَ ٱلَّذِى وَفَّىٰٓ", transliteration: "Waibraheema allathee waffa", transliterationB: "Wa Ibraaheemal lazee waffaaa", english: "And of Abraham who fulfilled his engagements", romanUrdu: "Aur us Ibrahim ke sahifon mein bayan hui hai jisne wafa ka haqq ada kar diya" },
    { number: 38, arabic: "أَلَّا تَزِرُ وَازِرَةٌۭ وِزْرَ أُخْرَىٰ", transliteration: "Alla taziru waziratun wizra okhra", transliterationB: "Allaa taziru waaziratunw wizra ukhraa", english: "Namely, that no bearer of burdens can bear the burden of another", romanUrdu: "Yeh ke koi bojh uthane wala dusre ka bojh nahin uthayega" },
    { number: 39, arabic: "وَأَن لَّيْسَ لِلْإِنسَٰنِ إِلَّا مَا سَعَىٰ", transliteration: "Waan laysa lilinsani illa ma saAAa", transliterationB: "Wa al laisa lil insaani illaa maa sa'aa", english: "That man can have nothing but what he strives for", romanUrdu: "Aur yeh ke Insaan ke liye kuch nahin hai magar woh jiski usne saii(koshish /Strive) ki hai" },
    { number: 40, arabic: "وَأَنَّ سَعْيَهُۥ سَوْفَ يُرَىٰ", transliteration: "Waanna saAAyahu sawfa yura", transliterationB: "Wa anna sa'yahoo sawfa yuraa", english: "That (the fruit of) his striving will soon come in sight", romanUrdu: "Aur yeh ke uski saii (koshih/strive/effort) anqareeb dekhi jayegi" },
    { number: 41, arabic: "ثُمَّ يُجْزَىٰهُ ٱلْجَزَآءَ ٱلْأَوْفَىٰ", transliteration: "Thumma yujzahu aljazaa alawfa", transliterationB: "Summa yujzaahul jazaaa 'al awfaa", english: "Then will he be rewarded with a reward complete", romanUrdu: "Aur uski puri jaza use di jayegi" },
    { number: 42, arabic: "وَأَنَّ إِلَىٰ رَبِّكَ ٱلْمُنتَهَىٰ", transliteration: "Waanna ila rabbika almuntaha", transliterationB: "Wa anna ilaa rabbikal muntahaa", english: "That to thy Lord is the final Goal", romanUrdu: "Aur yeh ke aakhir-e-kaar pahunchna tere Rubb hi ke paas hai" },
    { number: 43, arabic: "وَأَنَّهُۥ هُوَ أَضْحَكَ وَأَبْكَىٰ", transliteration: "Waannahu huwa adhaka waabka", transliterationB: "Wa annahoo huwa adhaka wa abkaa", english: "That it is He Who granteth Laughter and Tears", romanUrdu: "Aur yeh ke usi ne hasaya aur usi ne rulaya" },
    { number: 44, arabic: "وَأَنَّهُۥ هُوَ أَمَاتَ وَأَحْيَا", transliteration: "Waannahu huwa amata waahya", transliterationB: "Wa annahoo huwa amaata wa ahyaa", english: "That it is He Who granteth Death and Life", romanUrdu: "Aur yeh ke usi ne maut di aur usi ne zindagi bakshi" },
    { number: 45, arabic: "وَأَنَّهُۥ خَلَقَ ٱلزَّوْجَيْنِ ٱلذَّكَرَ وَٱلْأُنثَىٰ", transliteration: "Waannahu khalaqa alzzawjayni alththakara waalontha", transliterationB: "Wa annahoo khalaqaz zawjainiz zakara wal unsaa", english: "That He did create in pairs,- male and female", romanUrdu: "Aur yeh ke usi ne narr (male) aur maada (female) ka joda paida kiya" },
    { number: 46, arabic: "مِن نُّطْفَةٍ إِذَا تُمْنَىٰ", transliteration: "Min nutfatin itha tumna", transliterationB: "Min nutfatin izaa tumnaa", english: "From a seed when lodged (in its place)", romanUrdu: "Ek boond (sperm-drop) se jab woh tapkayi jati hai" },
    { number: 47, arabic: "وَأَنَّ عَلَيْهِ ٱلنَّشْأَةَ ٱلْأُخْرَىٰ", transliteration: "Waanna AAalayhi alnnashata alokhra", transliterationB: "Wa anna 'alaihin nash atal ukhraa", english: "That He hath promised a Second Creation (Raising of the Dead)", romanUrdu: "Aur yeh ke dusri zindagi bakshna bhi usi ke zimme hai" },
    { number: 48, arabic: "وَأَنَّهُۥ هُوَ أَغْنَىٰ وَأَقْنَىٰ", transliteration: "Waannahu huwa aghna waaqna", transliterationB: "Wa annahoo huwa aghnaa wa aqnaa", english: "That it is He Who giveth wealth and satisfaction", romanUrdu: "Aur yeh ke usi ne gani (enriches) kiya aur jaidad bakshi" },
    { number: 49, arabic: "وَأَنَّهُۥ هُوَ رَبُّ ٱلشِّعْرَىٰ", transliteration: "Waannahu huwa rabbu alshshiAAra", transliterationB: "Wa annahoo huwa rabbush shi'raa", english: "That He is the Lord of Sirius (the Mighty Star)", romanUrdu: "Aur yeh ke wahi sheraa (Sirius / mighty star) ka Rubb hai" },
    { number: 50, arabic: "وَأَنَّهُۥٓ أَهْلَكَ عَادًا ٱلْأُولَىٰ", transliteration: "Waannahu ahlaka AAadan aloola", transliterationB: "Wa annahooo ahlak a 'Aadanil oolaa", english: "And that it is He Who destroyed the (powerful) ancient 'Ad (people)", romanUrdu: "Aur yeh ke usi ne Aad-e-oola (people of Aad) ko halaak kiya" },
    { number: 51, arabic: "وَثَمُودَا۟ فَمَآ أَبْقَىٰ", transliteration: "Wathamooda fama abqa", transliterationB: "Wa samooda famaaa abqaa", english: "And the Thamud nor gave them a lease of perpetual life", romanUrdu: "Aur samood ko aisa mitaya ke unmein se kisi ko baaki na choda" },
    { number: 52, arabic: "وَقَوْمَ نُوحٍۢ مِّن قَبْلُ ۖ إِنَّهُمْ كَانُوا۟ هُمْ أَظْلَمَ وَأَطْغَىٰ", transliteration: "Waqawma noohin min qablu innahum kanoo hum athlama waatgha", transliterationB: "Wa qawma Noohim min qablu innahum kaanoo hum azlama wa atghaa", english: "And before them, the people of Noah, for that they were (all) most unjust and most insolent transgressors", romanUrdu: "Aur unse pehle qaum-e-Nooh ko tabaah kiya kyunke woh thay hi sakht zaalim-o-sarkash log" },
    { number: 53, arabic: "وَٱلْمُؤْتَفِكَةَ أَهْوَىٰ", transliteration: "Waalmutafikata ahwa", transliterationB: "Wal mu'tafikata ahwaa", english: "And He destroyed the Overthrown Cities (of Sodom and Gomorrah)", romanUrdu: "Aur aundhi girne wali bastiyon ko utha phenka. (Qaum-e-Lut)" },
    { number: 54, arabic: "فَغَشَّىٰهَا مَا غَشَّىٰ", transliteration: "Faghashshaha ma ghashsha", transliterationB: "Faghashshaahaa maa ghashshaa", english: "So that (ruins unknown) have covered them up", romanUrdu: "Phir chaa diya unpar woh kuch jo (tum jaante hi ho ke) kya chaa diya" },
    { number: 55, arabic: "فَبِأَىِّ ءَالَآءِ رَبِّكَ تَتَمَارَىٰ", transliteration: "Fabiayyi alai rabbika tatamara", transliterationB: "Fabi ayyi aalaaa'i Rabbika tatamaaraa", english: "Then which of the gifts of thy Lord, (O man,) wilt thou dispute about", romanUrdu: "Pas aey mukhatib, apne Rubb ki kin kin niyamaton mein tu shakk karega" },
    { number: 56, arabic: "هَٰذَا نَذِيرٌۭ مِّنَ ٱلنُّذُرِ ٱلْأُولَىٰٓ", transliteration: "Hatha natheerun mina alnnuthuri aloola", transliterationB: "Haazaa nazeerum minan nuzuril oolaa", english: "This is a Warner, of the (series of) Warners of old", romanUrdu: "Yeh ek tambeeh (warning) hai pehle aaye huye tambihaat(warnings) mein se" },
    { number: 57, arabic: "أَزِفَتِ ٱلْءَازِفَةُ", transliteration: "Azifati alazifatu", transliterationB: "Azifatil laazifah", english: "The (Judgment) ever approaching draws nigh", romanUrdu: "Aane wali ghadi qareeb aa lagi hai" },
    { number: 58, arabic: "لَيْسَ لَهَا مِن دُونِ ٱللَّهِ كَاشِفَةٌ", transliteration: "Laysa laha min dooni Allahi kashifatun", transliterationB: "Laisa lahaa min doonil laahi kaashifah", english: "No (soul) but Allah can lay it bare", romanUrdu: "Allah ke siwa koi usko hatane wala nahin" },
    { number: 59, arabic: "أَفَمِنْ هَٰذَا ٱلْحَدِيثِ تَعْجَبُونَ", transliteration: "Afamin hatha alhadeethi taAAjaboona", transliterationB: "Afamin hazal hadeesi ta'jaboon", english: "Do ye then wonder at this recital", romanUrdu: "Ab kya yahi woh baatein hain jinpar tum izhaar- e-taajub karte ho" },
    { number: 60, arabic: "وَتَضْحَكُونَ وَلَا تَبْكُونَ", transliteration: "Watadhakoona wala tabkoona", transliterationB: "Wa tadhakoona wa laa tabkoon", english: "And will ye laugh and not weep", romanUrdu: "Hanste(laugh) ho aur rotey (weep) nahin ho" },
    { number: 61, arabic: "وَأَنتُمْ سَٰمِدُونَ", transliteration: "Waantum samidoona", transliterationB: "Wa antum saamidoon", english: "Wasting your time in vanities", romanUrdu: "Aur gaa (singing) bajaa kar inhein taalte ho" },
    { number: 62, arabic: "فَٱسْجُدُوا۟ لِلَّهِ وَٱعْبُدُوا۟ ۩", transliteration: "Faosjudoo lillahi waoAAbudoo", transliterationB: "Fasjudoo lillaahi wa'budoo", english: "But fall ye down in prostration to Allah, and adore (Him)", romanUrdu: "Jhuk jao Allah ke aagey aur bandagi baja laaoo (ayat-e-sajda)" }
  ]
};
